var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`새로운 장소에서 새로운 사람들을 만나도 좋다고 생각해.`,JPN:`新しい場所で新しい人に会うのもいいと思うんだ。`,ENG:`They're not half bad. New places, new connections.`,TWN:`They're not half bad. New places, new connections.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`왜냐면, 여자로서 한창 성장 중인 걸. 죠니를 사로잡을 만큼 멋진 여자가 되는 길은 멀고도 험하거든.`,JPN:`ジョニーを虜にするくらい良い女になりたいからね。`,ENG:`Because, I'm still growing as a woman. It's not an easy road to becoming a suitable match for Johnny!`,TWN:`Because, I'm still growing as a woman. It's not an easy road to becoming a suitable match for Johnny!`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`헤헤, 멋진 여자라는 게 뭔지 아직은 잘 모르겠지만.`,JPN:`へへ、良い女がどんなものか、まだよくわかってないけど。`,ENG:`He he, although I'm still not sure what being a suitable match is.`,TWN:`He he, although I'm still not sure what being a suitable match is.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`……나만의 매력? 으음~ 그런 게 있을까?`,JPN:`……僕だけの魅力？　う～ん、そんなのあるかな？`,ENG:`...My unique charm? Umm... I wonder if there's any.`,TWN:`...My unique charm? Umm... I wonder if there's any.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`아, 맞아! 최근 들어 나, 부쩍 성장했으니까!`,JPN:`あ、そうだ！　最近ぐっと成長したから！`,ENG:`Oh, right! I've grown a lot recently!`,TWN:`Oh, right! I've grown a lot recently!`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`예전에는 없었던 성숙한 매력을 발휘한다면 죠니도 좋아하려나?`,JPN:`前にはなかったオトナな一面を見せたらジョニーも振り向くかな？`,ENG:`Maybe if I start acting mature, Johnny will like it!`,TWN:`Maybe if I start acting mature, Johnny will like it!`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`좋아! 그럼 포즈부터 시작해 볼게! 아리스가와 씨랑 야마다 씨한테도 도와 달라고 하자!`,JPN:`よし！　それじゃあ、ポーズから始めてみるね！　有栖川さんと山田さんにも手伝ってもらおう！`,ENG:`All right! Then I'll start with poses! Let's ask Yamada and Arisugawa to help!`,TWN:`All right! Then I'll start with poses! Let's ask Yamada and Arisugawa to help!`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MAY_COLLABO_NULL_NULL`,text:{KOREA:`사인? 응! 그럼 얼마나 매력 넘치는지 감상 들려 주기야?`,JPN:`どう？　魅力的だった？　感想聞かせてよね！`,ENG:`An autograph? Okay! Promise you'll tell me how attractive I am in return.`,TWN:`An autograph? Okay! Promise you'll tell me how attractive I am in return.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MAY_COLLABO_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};